#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
ll l,r,len,num[35],dp[35][35][35];
/*
x  第几位 从个位到高位（dfs是从高位到个位的）
cnt0 0的个数
cnt1 1的个数 
limit 是否受到最大值的限制 
beg0 （1代表前面出现过非0数字 ，0代表前面全是前导0） 
*/
ll dfs(ll x,ll cnt0,ll cnt1,ll limit,ll beg0)
{
	if(!x) return (cnt0>=cnt1);
	if((!limit)&&beg0&&(dp[x][cnt0][cnt1]!=-1)) return dp[x][cnt0][cnt1];
	int mx=(limit)?num[x]:1;
	ll cnt=0;
	for(int i=0;i<=mx;i++)
	{
		ll ncnt0=cnt0,ncnt1=cnt1;
		if(beg0||(i==1))
		{
			if(i==0) ncnt0++;
			else ncnt1++;
		}
		cnt+=dfs(x-1,ncnt0,ncnt1,limit&&(i==mx),beg0||i);
	}
	if((!limit)&&beg0) dp[x][cnt0][cnt1]=cnt;//这里不能删掉前面的if
	return cnt;
}
ll solve(ll x)
{
//	int len;
	for(len=1;x;x/=2,len++)
	{
		num[len]=x%2;
	}
	return dfs(len-1,0,0,1,0);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	memset(dp,-1,sizeof(dp));
	cin>>l>>r;
	cout<<solve(r)-solve(l-1);
	return 0;
}
